### 2. **Backend API Endpoints**
Create endpoints to fetch privilege log data and generate CSV and PDF outputs.

#### Example Backend Endpoint:
```python
from flask import Flask, request, jsonify, Response
import csv
from io import StringIO

app = Flask(__name__)

@app.route('/get_privilege_logs', methods=['GET'])
def get_privilege_logs():
    conn = psycopg2.connect("dbname=your_dbname user=your_username password=your_password host=your_host")
    cursor = conn.cursor()

    query = "SELECT * FROM privilege_log"
    cursor.execute(query)
    logs = cursor.fetchall()

    conn.close()
    return jsonify(logs)

@app.route('/export_privilege_logs', methods=['GET'])
def export_privilege_logs():
    conn = psycopg2.connect("dbname=your_dbname user=your_username password=your_password host=your_host")
    cursor = conn.cursor()

    query = "SELECT * FROM privilege_log"
    cursor.execute(query)
    logs = cursor.fetchall()

    # CSV Export
    csv_data = StringIO()
    writer = csv.writer(csv_data)
    writer.writerow(['ID', 'Document ID', 'Review Hash', 'Custodian ID', 'Collection Date',
                     'Prediction Score', 'Predicted Label', 'Review Date', 'Reviewer ID',
                     'Override Flag', 'Override Reason', 'Action Type', 'Timestamp'])

    for log in logs:
        writer.writerow(log)

    csv_data.seek(0)

    # PDF Export
    pdf_data = generate_pdf(logs)  # Assume this function generates a PDF

    conn.close()

    return Response(pdf_data, mimetype='application/pdf')

def generate_pdf(data):
    from fpdf import FPDF

    pdf = FPDF()
    pdf.add_page()
    pdf.set_font("Arial", size=12)

    row_widths = [30, 50, 60, 40, 40, 40, 40, 40, 40, 40, 40, 40]
    header = ['ID', 'Document ID', 'Review Hash', 'Custodian ID', 'Collection Date',
              'Prediction Score', 'Predicted Label', 'Review Date', 'Reviewer ID',
              'Override Flag', 'Override Reason', 'Action Type', 'Timestamp']

    pdf.cell(sum(row_widths), 10, "Privilege Logs", border=1)
    pdf.ln(10)

    for i in range(len(header)):
        pdf.cell(row_widths[i], 10, header[i], border=1)

    pdf.ln()

    for log in data:
        for i in range(len(log)):
            pdf.cell(row_widths[i], 10, str(log[i]), border=1)

        pdf.ln()

    return pdf.output(dest='S')

if __name__ == '__main__':
    app.run(debug=True)
```

